#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, x;
        scanf("%d", &n);
        int *arr = (int*)malloc((n + 1) * sizeof(int));
        for (int i = 0; i < n; ++i) {
            scanf("%d", &arr[i]);
        }
        scanf("%d", &x);
        int i = n - 1;
        while (i >= 0 && arr[i] > x) {
            arr[i + 1] = arr[i];
            --i;
        }
        arr[i + 1] = x;
        for (int j = 0; j <= n; ++j) {
            if (j) printf(" ");
            printf("%d", arr[j]);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

